CLIGo SDKMCP Server <pre><code># Install
go install github.com/plexusone/agent-code-review/cmd/acr@latest

# Set up auth
export GITHUB_TOKEN=ghp_xxxxxxxxxxxx

# Review a PR
acr review 123 -o owner -r repo -e APPROVE -b "LGTM!"
</code></pre> <pre><code>import "github.com/plexusone/agent-code-review/pkg/review"

client := review.NewClientFromToken(ctx, token)
result, _ := client.Approve(ctx, "owner", "repo", 123, "LGTM!")
</code></pre> <p>Add to Claude Code MCP config:</p> <pre><code>{
  "mcpServers": {
    "code-review": {
      "command": "acr",
      "args": ["serve"]
    }
  }
}
</code></pre>
